using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly string[] _allowedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".pdf", ".doc", ".docx", ".xls", ".xlsx" };
    private readonly long _maxFileSize = 5 * 1024 * 1024; // 5 MB

    [HttpPost("upload")]
    public async Task<IActionResult> UploadFile(IFormFile file)
    {
        if (file == null || file.Length == 0)
            return BadRequest("No file uploaded.");

        if (file.Length > _maxFileSize)
            return BadRequest("File size exceeds the limit.");

        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
        if (!Array.Exists(_allowedExtensions, e => e == extension))
            return BadRequest("Invalid file type.");

        var uploadsPath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads");
        if (!Directory.Exists(uploadsPath))
            Directory.CreateDirectory(uploadsPath);

        var fileName = Path.GetFileNameWithoutExtension(file.FileName);
        var safeFileName = Path.Combine(uploadsPath, $"{fileName}_{Guid.NewGuid()}{extension}");

        using (var stream = new FileStream(safeFileName, FileMode.Create))
        {
            await file.CopyToAsync(stream);
        }

        var filePath = $"/uploads/{Path.GetFileName(safeFileName)}";
        return Ok(new { FilePath = filePath });
    }
}